3	const BASE_PREMIUMS: Record<string, number> = {
4	  Sword: 100,
5	  Amulet: 60,
6	  Staff: 80,
7	  Potion: 40,
8	  Rune: 25,
9	  Moonstone: 25,
10	};
11	
12	const FIRST_INSURANCE_PERCENT = 110;
13	const PROCESSING_FEE = 5;
14	
15	type Item = { type: string };
16	
17	const quotePremium = (items: Item[]): number => {
18	  const baseTotal = items.reduce(
19	    (total, item) => total + BASE_PREMIUMS[item.type],
20	    0,
21	  );
22	  const withFirstInsurance = (baseTotal * FIRST_INSURANCE_PERCENT) / 100;
23	  return Math.ceil(withFirstInsurance + PROCESSING_FEE);
24	};
25	
26	export function processScenario(scenario: any): unknown {
27	  const [{ items }] = scenario.steps;
28	  return { results: [{ premium: quotePremium(items) }] };
29	}
